window.Split=function(elements,options){var left=document.querySelector(elements[0]),right=document.querySelector(elements[1]);if(!left||!right)return;var gutter=document.createElement("div");gutter.className="gutter";left.after(gutter);var dragging=false;gutter.addEventListener("mousedown",function(){dragging=true;document.body.classList.add("is-resizing")});document.addEventListener("mouseup",function(){dragging=false;document.body.classList.remove("is-resizing")});document.addEventListener("mousemove",function(event){if(!dragging)return;var min=(options&&options.minSize)||240;var max=520;var width=Math.max(min,Math.min(max,event.clientX));left.style.width=width+"px";right.style.width="calc(100% - "+width+"px)"});};
